(()=>{'use strict';
const PUBLIC_ACTIVE_ENDPOINT='https://saodmeoilixfdqentofp.supabase.co/functions/v1/doit-active';
const $=s=>document.querySelector(s);
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH');
const E=s=>T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const K=s=>T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'');
let rawRows=[],metaCount=0,loading=false,loadedCloud=false,lastCount=0,lastMode='none';
function cleanPs(v){const p=T(v).split(/\s+/).filter(Boolean);if(p.length===2&&p[0]===p[1])return p[0];const out=[];p.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function col(o,names){const ks=Object.keys(o||{}),mp=new Map(ks.map(k=>[K(k),k]));for(const x of names){const k=mp.get(K(x));if(k)return k}for(const k of ks)for(const x of names)if(K(k).includes(K(x))||K(x).includes(K(k)))return k}
function val(o,names,d=''){const k=col(o,names);return k?T(o[k])||d:d}
function keyLooksTele(k){return /tele|telesale|telesales|telesalesperson|tele_sale|tele_sales|โทร|เทเล/i.test(T(k))}
function valLooksTele(v){return /tele|telesale|telesales|โทร|เทเล/i.test(T(v))}
function teleValue(o){return val(o,['tele','isTele','is_tele','telesale','telesales','teleSale','teleSales','telesaleName','telesalesName','teleSaleName','teleSalesName','telesale_id','telesaleId','TelesaleId','TelesalesID','TeleSaleID','TeleSalesID'])}
function psValue(o){return cleanPs(val(o,['ps','PS','salesperson','salespersonName','Salesperson_Name','Salesperson Name','SO_SalespersonID','SalespersonID','PS Code'])||'')}
function invValue(o){return val(o,['inv','invoice','invoiceNo','InvoiceNo','InvcNbr','bill','billNo','orderNo','SO No','SONo'])||'-'}
function storeValue(o){return val(o,['store','customer','customerName','CustomerName','ShipName','Ship To Name','c_Name','BranchName'])||'-'}
function dateValue(o){return val(o,['date','InvcDate','InvoiceDate','invoiceDate','ShipDate','OrderDate'])||'-'}
function looksTeleRow(o){if(!o||typeof o!=='object')return false;const direct=teleValue(o);if(direct&&String(direct).toLowerCase()!=='false'&&String(direct)!=='0')return true;if(o.isTele===true||o.is_tele===true||o.is_telesale===true)return true;if(valLooksTele(val(o,['type','SOTypeID','DocType','OrderType'])))return true;return Object.keys(o).some(k=>keyLooksTele(k)&&T(o[k])&&String(o[k]).toLowerCase()!=='false'&&String(o[k])!=='0')}
function scope(){const psDom=cleanPs($('#psSelect')?.value);const list=(window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean);const dates=(window.DOIT_SELECTED_DATES||[]).map(T).filter(Boolean);return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),psList:list.length?list:(psDom?[psDom]:[]),dates}}
function inScope(r){const s=scope(),d=dateValue(r),ps=psValue(r);if(!looksTeleRow(r))return false;if(s.dates.length&&!s.dates.includes(d))return false;if(!s.dates.length&&s.start&&d<s.start)return false;if(!s.dates.length&&s.end&&d>s.end)return false;if(s.psList.length&&!s.psList.includes(ps))return false;return true}
function computedBills(){const allTele=(rawRows||[]).filter(looksTeleRow);const scoped=allTele.filter(inScope);const set=new Set(scoped.map(r=>[invValue(r),storeValue(r),teleValue(r)||'Telesale',dateValue(r)].join('|')));return{rows:scoped.length,bills:set.size,totalTeleRows:allTele.length,totalRows:(rawRows||[]).length}}
async function fetchCloudRows(){if(loading||loadedCloud)return;loading=true;try{const m=await fetch(PUBLIC_ACTIVE_ENDPOINT+'?mode=data',{headers:{Accept:'application/json'}});if(!m.ok)throw Error('meta http '+m.status);const packet=await m.json();metaCount=N(packet.active?.telesale_bill_count||0);let payload=null;if(packet.mode==='json_url'&&packet.url){const r=await fetch(packet.url,{headers:{Accept:'application/json'}});if(!r.ok)throw Error('json http '+r.status);payload=await r.json()}else if(packet.payload){payload=packet.payload}const arr=payload?.rows||payload||[];if(Array.isArray(arr)&&arr.length){rawRows=arr;loadedCloud=true;window.__doitTeleRows316=rawRows}}catch(e){console.warn('[telesale-count-fix-v316] cloud rows failed',e)}finally{loading=false;updateBtn()}}
function patchJsonApp(){const app=window.DOIT_JSON_APP;if(!app||app.__tele316)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{try{const arr=payload?.rows||payload||[];if(Array.isArray(arr)&&arr.length){rawRows=arr;window.__doitTeleRows316=rawRows}metaCount=N(m.telesale_bill_count||m.telesale_bills||payload?.meta?.telesale_bill_count||metaCount);setTimeout(updateBtn,0);setTimeout(updateBtn,300);setTimeout(updateBtn,1200);fetchCloudRows()}catch(e){}return old(payload,m)};app.__tele316=true;return true}
function ensureBtn(){const a=document.querySelector('.actions');let b=$('#teleBillsBtn');if(!b&&a){b=document.createElement('button');b.id='teleBillsBtn';b.className='teleBtn';b.type='button';a.prepend(b)}return b}
function updateBtn(){const b=ensureBtn();if(!b)return;const c=computedBills();const s=scope();let n=c.bills;if(!n&&!s.psList.length&&metaCount){n=metaCount;lastMode='cloud-meta-all'}else if(c.totalTeleRows){lastMode='json-rows-filtered'}else if(s.psList.length){lastMode='no-row-detail-for-ps'}else{lastMode='zero'}lastCount=n;const txt=`บิล Telesale (${F(n)})`;if(b.textContent!==txt)b.textContent=txt;b.onclick=openDebug;b.dataset.tele316=lastMode}
function openDebug(){let body=$('#teleBody');if(!body)return alert(`Telesale fix v316\nจำนวนบิล: ${F(lastCount)}\nแหล่งข้อมูล: ${lastMode}`);const c=computedBills(),s=scope();body.innerHTML=`<div class="teleScope">Telesale fix v316<div class="teleScopeDebug">PS ที่เลือก: ${E(s.psList.join(', ')||'ทั้งหมด')}<br>จำนวนตาม PS/วันที่: ${F(c.bills)} บิล / ${F(c.rows)} แถว<br>Tele ทั้งไฟล์จาก JSON: ${F(c.totalTeleRows)} แถว<br>Cloud metadata รวมทั้งไฟล์: ${F(metaCount)} บิล<br>ใช้แสดงปุ่มจาก: ${E(lastMode)}<br>Raw rows: ${F(c.totalRows)}</div></div>`+(c.bills?'<div class="teleEmpty">นับตาม PS/วันที่จาก JSON rows แล้ว</div>':'<div class="teleEmpty">ไม่พบ Telesale ตาม PS/วันที่นี้ หรือ JSON ไม่มีรายละเอียด Tele แยก PS</div>');$('#teleShade')?.classList.add('on');$('#teleDrawer')?.classList.add('on');updateBtn()}
function bind(){['psSelect','startDate','endDate'].forEach(id=>{const el=$('#'+id);if(el&&!el.dataset.tele316){el.dataset.tele316='1';el.addEventListener('change',()=>setTimeout(updateBtn,80),true)}});['doit:psChanged','doit:selectedDatesChanged','doit:scopeRendered','doit:stateChanged'].forEach(ev=>document.addEventListener(ev,()=>setTimeout(updateBtn,100)))}
function boot(){patchJsonApp();bind();updateBtn();fetchCloudRows();let n=0;const tick=()=>{patchJsonApp();bind();updateBtn();if(++n<300)setTimeout(tick,1000)};setTimeout(tick,300)}
window.DOIT_TELESALE_META_FIX={version:'v316',debug:()=>({rawRows:rawRows.length,metaCount,computed:computedBills(),lastCount,lastMode,loadedCloud,scope:scope()})};
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();